   634→// ─── V2 full-tree indexer ─────────────────────────────────────────────────────
   635→
   636→export async function indexAllCheckpointsV2(
   637→  db: PrismaClient,
   638→  rootDir: string,
   639→  onProgress?: (checkpointId: string) => void,
   640→  repoPath?: string,
   641→): Promise<{ checkpoints: number }> {
   642→  let totalCheckpoints = 0;
   643→
   644→  // Pre-fetch all checkpoint IDs that already have a git OID mapping so we
   645→  // can skip the per-checkpoint DB read inside saveGitOidMapping.
   646→  let mappedCheckpointIds: Set<string> | undefined;
   647→  if (repoPath) {
   648→    const rows = await db.checkpointIdGitOidJoin.findMany({ select: { checkpointId: true } });
   649→    mappedCheckpointIds = new Set(rows.map((r) => r.checkpointId));
   650→  }
   651→
   652→  const shards = readdirSync(rootDir)
   653→    .filter((e) => /^[0-9a-f]{2}$/i.test(e) && statSync(join(rootDir, e)).isDirectory());
   654→
   655→  for (const shard of shards) {
   656→    const shardPath = join(rootDir, shard);
   657→    const ids = readdirSync(shardPath)
   658→      .filter((e) => /^[0-9a-f]{10}$/i.test(e) && statSync(join(shardPath, e)).isDirectory());
   659→
   660→    for (const rest of ids) {
   661→      const checkpointId  = shard + rest;
   662→      const checkpointDir = join(shardPath, rest);
   663→      try {
   664→        await indexCheckpointV2(db, checkpointDir, checkpointId, repoPath, mappedCheckpointIds);
   665→        mappedCheckpointIds?.add(checkpointId); // keep set current for this pass
   666→        totalCheckpoints++;
   667→        onProgress?.(checkpointId);
   668→      } catch (err) {
   669→        process.stderr.write(`indexer-v2: skipping ${checkpointId}: ${err}\n`);
   670→      }
   671→    }
   672→  }
   673→
   674→  // Sync FTS index with any new LogContent rows added during this pass
   675→  await setupLogContentFts(db);
   676→  await syncLogContentFts(db);
   677→
   678→  return { checkpoints: totalCheckpoints };
   679→}
   680→
   681→// ─── Full-tree indexer ───────────────────────────────────────────────────────
   682→
   683→/**
   684→ * Walk a checkpoints root directory and index every checkpoint found.
   685→ *
   686→ * The root must have the shard structure:
   687→ *   <root>/<2-hex-chars>/<10-hex-chars>/
   688→ *
   689→ * @param onProgress  Optional callback called after each checkpoint.
   690→ */
   691→export async function indexAllCheckpoints(
   692→  db: PrismaClient,
   693→  rootDir: string,
   694→  onProgress?: (checkpointId: string) => void,
   695→  repoPath?: string,
   696→): Promise<{ checkpoints: number }> {
   697→  const result = await indexAllCheckpointsV2(db, rootDir, onProgress, repoPath);
   698→  return { checkpoints: result.checkpoints };
   699→}
